ast.source:
.nexus-merge-summary {
    margin-bottom: 20px;
}
.nexus-merge-stats p {
    margin: 8px 0;
    font-size: 14px;
}
.nexus-merge-warning {
    color: var(--text-warning);
}
.nexus-merge-error {
    color: var(--text-error);
}
.nexus-merge-explanation {
    padding: 12px;
    background: var(--background-secondary);
    border-radius: 4px;
    margin: 16px 0;
}
.nexus-merge-errors {
    margin-top: 16px;
    padding: 12px;
    background: var(--background-modifier-error);
    border-radius: 4px;
}
.nexus-merge-errors ul {
    margin: 8px 0;
    padding-left: 20px;
}
.nexus-merge-errors li {
    margin: 4px 0;
    font-size: 12px;
    font-family: var(--font-monospace);
}

